"""
Represents the 8x8 grid of a Checkers (Draughts) game.
"""

class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_pieces()

    def initialize_pieces(self):
        # Place pieces on the board
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece("white")
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece("black")

    def get_piece(self, row, col):
        return self.board[row][col]

    def set_piece(self, row, col, piece):
        self.board[row][col] = piece

    def move_piece(self, from_row, from_col, to_row, to_col):
        if 0 <= from_row < 8 and 0 <= from_col < 8 and 0 <= to_row < 8 and 0 <= to_col < 8:
            piece = self.get_piece(from_row, from_col)
            if piece:
                self.set_piece(to_row, to_col, piece)
                self.set_piece(from_row, from_col, None)

    def print_board(self):
        for row in self.board:
            for piece in row:
                if piece:
                    print(f"{piece.color[0].upper()}", end=" ")
                else:
                    print(".", end=" ")
            print()
```

