"""
Represents a player, with methods for making moves and capturing pieces.
"""

class Player:
    def __init__(self, color):
        self.color = color

    def make_move(self, board, from_pos, to_pos):
        if isinstance(board.get_piece(*from_pos), Piece) and \
           board.get_piece(*from_pos).color == self.color:
