"""
Manages the game state, including whose turn it is, checking for legal moves,
and detecting win/draw conditions.
"""

from board import Board
from player import Player

class Game:
    def __init__(self):
        self.board = Board()
        self.players = [Player("black"), Player("white")]
        self.current_player_index = 0

    def switch_turn(self):
        self.current_player_index = (self.current_player_index + 1) % 2

    def play_game(self):
        while True:
            print(f"Current player: {self.players[self.current_player_index].color.upper()}")
            self.board.print_board()
            from_pos = tuple(map(int, input("Enter the piece's position (row col): ").split()))
            to_pos = tuple(map(int, input("Enter the destination position (row col): ").split()))
            if self.is_valid_move(from_pos, to_pos):
                self.players[self.current_player_index].make_move(self.board, from_pos, to_pos)
                self.switch_turn()
            else:
                print("Invalid move. Try again.")

    def is_valid_move(self, from_pos, to_pos):
        piece = self.board.get_piece(*from_pos)
        if piece and piece.color == self.players[self.current_player_index].color:
            # Add logic to check for valid moves based on rules
            return True
        return False

if __name__ == "__main__":
    game = Game()
    game.play_game()
